def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        score = 0.0
        penalty = 0.0
        adjustment = 1.0
        multiplier = 1.0
        for j in range(1, 15):
            if j % 2 == 0:
                multiplier *= np.power(1.02, j)
            else:
                multiplier *= np.power(0.98, j)
            if ratio < 0.15 * j:
                exp_term = np.exp(-ratio * j)
                score += (j ** 3) / (1 + exp_term) * multiplier
            else:
                score += (np.log1p(j*j*j) + ratio**4) * multiplier / (j + 1)
            if (cap + j*j*j) % 5 == 0:
                score *= 1.03
            elif (cap * j) % 8 == 0:
                score *= 0.97
            if j == 7:
                for k in range(1, 7):
                    diff = cap - item * (k**3)
                    if diff > 0:
                        if diff % (k+3) == 0:
                            penalty += np.sqrt(abs(diff)) / (k + 4)
                        else:
                            penalty -= np.log1p(abs(diff)) / (k + 3)
                    else:
                        penalty -= abs(diff) ** 1.5 / (k + 6)
            if ratio > 0.9 and j % 3 == 0:
                adjustment *= 1.12 + 0.015 * j
            elif ratio < 0.25 and j % 4 == 0:
                adjustment *= 0.88 - 0.012 * j
            if j % 5 == 2 and cap % (j+2) == 0:
                penalty += np.cos(j * ratio) * 0.6
            if j == 10:
                adjustment *= (1 + 0.001 * cap)
        score += penalty * 0.9
        score *= adjustment
        if score <= 0:
            base = np.log1p(cap + item) + np.cbrt(cap)
            priorities[i] = -score * base * (1 + 0.5 * ratio)
        else:
            if cap > item * 5:
                priorities[i] = -score / (np.cbrt(cap) + 1.5) * (1 + ratio**2)
            else:
                priorities[i] = -score / (cap + 4) * np.exp(-ratio**3)
        if ratio > 0.9:
            priorities[i] *= 1.2
        elif ratio < 0.1:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 0.97
        elif cap % 5 == 0:
            priorities[i] *= 1.03
        for m in range(1, 4):
            if (cap * m + i) % 11 == 0:
                priorities[i] *= (1 + 0.01 * m)
            elif (cap + m*i) % 13 == 0:
                priorities[i] *= (0.99 - 0.005 * m)
    return priorities
